import{_ as o,C as n,o as s,c as l,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Malta","description":"Immigration pathways and relocation guide for transgender people moving to Malta","frontmatter":{"layout":"doc","title":"Moving to Malta","description":"Immigration pathways and relocation guide for transgender people moving to Malta"},"headers":[],"relativePath":"europe/malta/moving-there.md","filePath":"europe/malta/moving-there.md","lastUpdated":null}'),g={name:"europe/malta/moving-there.md"};function h(c,t,m,u,p,f){const e=n("Badge");return s(),l("div",null,[a(e,{variant:"green"},{default:i(()=>[...t[0]||(t[0]=[r("EU Free Movement",-1)])]),_:1}),a(e,{variant:"yellow"},{default:i(()=>[...t[1]||(t[1]=[r("English Widely Spoken",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="moving-to-malta" tabindex="-1">Moving to Malta <a class="header-anchor" href="#moving-to-malta" aria-label="Permalink to &quot;Moving to Malta&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>As an EU member state, Malta grants free movement to EU/EEA/Swiss citizens. Registration with the authorities is required for stays over three months.</p><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Visa</td><td>Employment with Maltese employer</td><td>Job offer, Employment Licence from Jobsplus</td><td>1 year, renewable</td></tr><tr><td>Nomad Residence Permit</td><td>Remote workers</td><td>€2,700/month minimum income, remote work proof</td><td>1 year, renewable</td></tr><tr><td>Global Residence Programme</td><td>Wealthy individuals</td><td>Property purchase/rent, tax remittance</td><td>5 years, renewable</td></tr><tr><td>Family Reunification</td><td>Family of residents</td><td>Relationship proof, sufficient income</td><td>1 year, renewable</td></tr><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance, funds proof</td><td>1 year, renewable</td></tr></tbody></table><h2 id="key-relocation-steps" tabindex="-1">Key Relocation Steps <a class="header-anchor" href="#key-relocation-steps" aria-label="Permalink to &quot;Key Relocation Steps&quot;">​</a></h2><ol><li><strong>Arrange accommodation</strong> — Rental market is competitive; start searching early</li><li><strong>Register with Identity Malta</strong> — For residence documentation</li><li><strong>Apply for residence card</strong> — Non-EU citizens require this</li><li><strong>Register with health services</strong> — Obtain an EU Health Insurance Card or register with the public system</li><li><strong>Open a bank account</strong> — Required for employment and daily life</li><li><strong>Register with Jobsplus</strong> — If seeking employment</li></ol><h2 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h2><p>Moderate to high, with significant regional variation:</p><ul><li>Rent (1-bedroom): €700-1,200/month</li><li>Groceries: €300-500/month</li><li>Public transport: Very cheap (€15-30/month pass)</li><li>Health insurance: Public healthcare is free at point of use; private insurance €300-800/year</li></ul><h2 id="trans-specific-relocation-tips" tabindex="-1">Trans-Specific Relocation Tips <a class="header-anchor" href="#trans-specific-relocation-tips" aria-label="Permalink to &quot;Trans-Specific Relocation Tips&quot;">​</a></h2><ul><li><strong>Malta is extremely safe</strong> for transgender people — lowest transphobia rates in Europe</li><li><strong>English is an official language</strong> — all medical and legal processes available in English</li><li><strong>Bring medical documentation</strong> in English</li><li><strong>Carry sufficient HRT medication</strong> for at least 3 months</li><li><strong>Contact MGRM</strong> for community support upon arrival</li><li><strong>Register with the Gender Wellbeing Clinic</strong> early — proactive registration is best</li></ul><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><ul><li><strong>Official languages</strong>: Maltese and English</li><li><strong>English is widely spoken</strong> by nearly the entire population</li><li><strong>Maltese</strong> is useful for integration but not essential for daily life</li><li>Citizenship requires a Maltese language test (typically after 5+ years of residence)</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Identity Malta</strong> — Immigration agency: <a href="https://www.identitymalta.com/" target="_blank" rel="noreferrer">identitymalta.com</a></li><li><strong>Jobsplus</strong> — Employment services: <a href="https://jobsplus.gov.mt/" target="_blank" rel="noreferrer">jobsplus.gov.mt</a></li><li><strong>MGRM</strong> — Trans/LGBTIQ+ support: <a href="https://www.maltagayrights.net/" target="_blank" rel="noreferrer">maltagayrights.net</a></li><li><strong>Visit Malta</strong> — Relocation guide: <a href="https://www.visitmalta.com/" target="_blank" rel="noreferrer">visitmalta.com</a></li></ul>',17))])}const w=o(g,[["render",h]]);export{b as __pageData,w as default};
